import { execFile } from "node:child_process";
import { readFile } from "node:fs/promises";
import { promisify } from "node:util";

const execFileAsync = promisify(execFile);

const generatedHeaders = [
  {
    file: "src/console/assets.generated.ts",
    prefix: [
      "// Generated by scripts/build-console-assets.mjs from Surface Console asset sources.",
      "// Do not edit directly; edit src/console/client/parts/ or src/console/styles/parts/ instead.",
    ].join("\n"),
  },
  {
    file: "src/console/client/index.js",
    prefix: [
      "// Generated by scripts/build-console-assets.mjs from src/console/client/parts/.",
      "// Do not edit directly; edit the ordered part files instead.",
    ].join("\n"),
  },
  {
    file: "src/console/styles/index.css",
    prefix: [
      "/* Generated by scripts/build-console-assets.mjs from src/console/styles/parts/.",
      "   Do not edit directly; edit the ordered part files instead.",
    ].join("\n"),
  },
  {
    file: "src/trust-panel/trust-panel-module.generated.ts",
    prefix: [
      "// Generated by scripts/build-trust-panel-module.mjs from dist/src/trust-panel/surface-trust-panel.js.",
      "// Do not edit directly; edit src/trust-panel/surface-trust-panel.ts and run npm run build:trust-panel-module.",
    ].join("\n"),
  },
];

const ignoredGeneratedOrRuntimePaths = [
  "dist/",
  "docs-site/",
  "test-results/",
  "playwright-report/",
  ".npm-pack-cache/",
  ".omx/",
  ".flow-agents/",
  ".surface/claims/",
  ".surface/reports/",
  ".surface/runs/",
  ".surface/cache/",
];

const generatedOrRuntimePathSegments = [
  ".flow-agents",
  ".npm-pack-cache",
  ".omx",
  "dist",
  "docs-site",
  "node_modules",
  "playwright-report",
  "test-results",
];

const trackedGeneratedOrRuntimePatterns = [
  /^dist\//,
  /^docs-site\//,
  /^test-results\//,
  /^playwright-report\//,
  /^\.npm-pack-cache\//,
  /^\.omx\//,
  /^\.flow-agents\//,
  /^\.surface\/(?:claims|reports|runs|cache)\//,
];

const packageFileForbiddenPatterns = [
  /^src\//,
  /^scripts\//,
  /^tests\//,
  /^docs-site\//,
  /^dist\/tests\//,
  /^\.agents\//,
  /^\.flow-agents\//,
  /^\.omx\//,
  /^\.npm-pack-cache\//,
];

const [gitignore, packageJsonText, trackedFilesText] = await Promise.all([
  readFile(".gitignore", "utf8"),
  readFile("package.json", "utf8"),
  execFileAsync("git", ["ls-files"], { maxBuffer: 1024 * 1024 * 5 }).then(({ stdout }) => stdout),
]);

const packageJson = JSON.parse(packageJsonText);
const packageFiles = packageJson.files ?? [];
const trackedFiles = trackedFilesText.split("\n").filter(Boolean);

for (const path of ignoredGeneratedOrRuntimePaths) {
  if (!gitignore.includes(path)) {
    throw new Error(`Missing generated/runtime ignore entry: ${path}`);
  }
}

if (gitignore.split(/\r?\n/).some((line) => line.trim() === ".agents/")) {
  throw new Error(".agents/ must not be gitignored; durable agent bundle files can be tracked.");
}

for (const file of trackedFiles) {
  const matched = trackedGeneratedOrRuntimePatterns.find((pattern) => pattern.test(file));
  if (matched) throw new Error(`Tracked generated/runtime artifact matched ${matched}: ${file}`);
  const pathSegment = generatedOrRuntimePathSegments.find((segment) => file.split("/").includes(segment));
  if (pathSegment) throw new Error(`Tracked generated/runtime artifact contains ${pathSegment}: ${file}`);
}

for (const fileEntry of packageFiles) {
  const matched = packageFileForbiddenPatterns.find((pattern) => pattern.test(fileEntry));
  if (matched) throw new Error(`package.json files entry should not publish ${matched}: ${fileEntry}`);
}

for (const { file, prefix } of generatedHeaders) {
  const source = await readFile(file, "utf8");
  if (!source.startsWith(prefix)) {
    throw new Error(`${file} is missing the expected generated-file header.`);
  }
}

console.log("Generated/runtime boundary check passed.");
